#[derive(Debug, Clone, PartialEq, Eq)]
enum PublicationTruthExportBlockerTopLevelState {
    GateSatisfied,
    ReplaySolLegIncomplete,
    OtherCheckpoint(String),
    IncompleteOrStaleWithoutCheckpointExplanation,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PublicationTruthExportCheckpointHeadlineOutcome {
    Completed { allow_deep_replay: bool },
    Failed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PublicationTruthExportCheckpointRowMetaStage {
    SchemaLookup,
    RowCount,
    PreparePrimaryKeyLookup,
    StepPrimaryKeyLookup,
}

impl PublicationTruthExportCheckpointRowMetaStage {
    fn as_str(self) -> &'static str {
        match self {
            Self::SchemaLookup => "load_persisted_rebuild_row_meta_schema_lookup",
            Self::RowCount => "load_persisted_rebuild_row_meta_row_count",
            Self::PreparePrimaryKeyLookup => {
                "load_persisted_rebuild_row_meta_prepare_primary_key_lookup"
            }
            Self::StepPrimaryKeyLookup => "load_persisted_rebuild_row_meta_step_primary_key_lookup",
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PublicationTruthExportCheckpointRowMeta {
    checkpoint_exists: bool,
    rebuild_phase: Option<String>,
    updated_at: Option<DateTime<Utc>>,
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct PublicationTruthExportCheckpointHeadlineTiming {
    total_elapsed_ms: u64,
    runtime_db_open_elapsed_ms: u64,
    schema_lookup_elapsed_ms: u64,
    row_count_elapsed_ms: u64,
    prepare_elapsed_ms: u64,
    step_elapsed_ms: u64,
    budget_remaining_ms_after_open: u64,
    budget_remaining_ms_after_schema_lookup: u64,
    budget_remaining_ms_after_row_count: u64,
    budget_remaining_ms_after_prepare: u64,
    budget_remaining_ms_after_step: u64,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum PublicationTruthExportCheckpointRowMetaLoadOutcome {
    Completed(PublicationTruthExportCheckpointRowMeta),
    BudgetExhausted(PublicationTruthExportCheckpointRowMetaStage),
    Error(String),
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct PublicationTruthExportCheckpointRowMetaLoadResult {
    outcome: PublicationTruthExportCheckpointRowMetaLoadOutcome,
    timing: PublicationTruthExportCheckpointHeadlineTiming,
    worker: PublicationTruthExportCheckpointHeadlineWorkerTelemetry,
}

#[derive(Debug, Clone, Default, PartialEq, Eq)]
struct PublicationTruthExportCheckpointHeadlineWorkerTelemetry {
    started: bool,
    last_event: Option<String>,
    event_count: u64,
    opened_read_only_received: bool,
    schema_lookup_completed_received: bool,
    row_count_completed_received: bool,
    prepare_completed_received: bool,
    step_query_started_received: bool,
    step_row_fetch_completed_received: bool,
    step_phase_decoded_received: bool,
    step_updated_at_decoded_received: bool,
    step_completed_received: bool,
    finished_send_attempted: bool,
    finished_received: bool,
    disconnected: bool,
    sqlite_busy_timeout_ms: Option<u64>,
    query_sql: Option<String>,
    explain_query_plan: Option<String>,
    explain_query_plan_rows: Option<Vec<String>>,
    query_readonly_mode: Option<bool>,
    connection_journal_mode: Option<String>,
    connection_locking_mode: Option<String>,
    connection_query_only: Option<bool>,
    row_fetch_access_path: Option<String>,
    row_fetch_wait_kind: Option<String>,
    row_fetch_started_at_unix_ms: Option<i64>,
    row_fetch_elapsed_ms_observed_by_worker: Option<u64>,
}

#[derive(Debug)]
enum PublicationTruthExportCheckpointRowMetaWorkerMessage {
    OpenedReadOnly(u64),
    SqliteBusyTimeoutMs(u64),
    ConnectionReadMode {
        journal_mode: String,
        locking_mode: String,
        query_only: bool,
    },
    QueryPlan {
        query_sql: String,
        explain_query_plan: String,
        explain_query_plan_rows: Vec<String>,
        query_readonly_mode: bool,
        row_fetch_access_path: String,
    },
    Entered(PublicationTruthExportCheckpointRowMetaStage),
    SchemaLookupCompleted(u64),
    RowCountCompleted(u64),
    PrepareCompleted(u64),
    StepQueryStarted(i64),
    StepRowFetchCompleted {
        elapsed_ms: u64,
        row_returned: bool,
    },
    StepPhaseDecoded,
    StepUpdatedAtDecoded,
    StepCompleted(u64),
    FinishedSendAttempted,
    Finished(Result<PublicationTruthExportCheckpointRowMeta, String>),
}

impl PublicationTruthExportCheckpointRowMetaWorkerMessage {
    fn event_name(&self) -> &'static str {
        match self {
            Self::OpenedReadOnly(_) => "opened_read_only",
            Self::SqliteBusyTimeoutMs(_) => "sqlite_busy_timeout_ms",
            Self::ConnectionReadMode { .. } => "connection_read_mode_loaded",
            Self::QueryPlan { .. } => "query_plan_loaded",
            Self::Entered(PublicationTruthExportCheckpointRowMetaStage::SchemaLookup) => {
                "entered_schema_lookup"
            }
            Self::Entered(PublicationTruthExportCheckpointRowMetaStage::RowCount) => {
                "entered_row_count"
            }
            Self::Entered(
                PublicationTruthExportCheckpointRowMetaStage::PreparePrimaryKeyLookup,
            ) => "entered_prepare_primary_key_lookup",
            Self::Entered(PublicationTruthExportCheckpointRowMetaStage::StepPrimaryKeyLookup) => {
                "entered_step_primary_key_lookup"
            }
            Self::SchemaLookupCompleted(_) => "schema_lookup_completed",
            Self::RowCountCompleted(_) => "row_count_completed",
            Self::PrepareCompleted(_) => "prepare_completed",
            Self::StepQueryStarted(_) => "step_query_started",
            Self::StepRowFetchCompleted { .. } => "step_row_fetch_completed",
            Self::StepPhaseDecoded => "step_phase_decoded",
            Self::StepUpdatedAtDecoded => "step_updated_at_decoded",
            Self::StepCompleted(_) => "step_completed",
            Self::FinishedSendAttempted => "finished_send_attempted",
            Self::Finished(_) => "finished",
        }
    }
}

fn export_gate_reason_publishable_checkpoint_blocker(reason: &str) -> Option<&str> {
    reason
        .strip_prefix(PUBLICATION_TRUTH_WITHHELD_PREFIX)
        .filter(|blocker| !blocker.is_empty())
}

fn infer_checkpoint_phase_and_subphase_from_blocker(
    blocker: &str,
) -> (Option<&'static str>, Option<&'static str>, Option<bool>) {
    match blocker {
        "replay_wallet_stats_incomplete" => (Some("replay"), Some("wallet_stats"), Some(true)),
        "replay_candidate_activity_backfill_incomplete" => {
            (Some("replay"), Some("activity_backfill"), Some(true))
        }
        "replay_sol_leg_incomplete" => (Some("replay"), Some("sol_leg"), Some(true)),
        "replay_post_wallet_stats_handoff_pending" => (Some("replay"), None, Some(true)),
        blocker if blocker.starts_with("collect_buy_mints_") => {
            (Some("collect_buy_mints"), None, Some(false))
        }
        blocker if blocker.starts_with("token_quality_") => {
            (Some("resolve_token_quality"), None, Some(false))
        }
        blocker if blocker.starts_with("publish_pending_") => {
            (Some("publish_pending"), None, Some(false))
        }
        _ => (None, None, None),
    }
}

