fn classify_publication_truth_export_blocker_from_publication_state(
    diagnostic: &mut PublicationTruthExportBlockerDiagnostic,
    publication_truth_complete: bool,
    fresh_under_export_gate: bool,
) -> PublicationTruthExportBlockerTopLevelState {
    diagnostic.publication_truth_export_blocker_observed = true;
    diagnostic.publication_truth_export_blocker_top_level_proven_from_publication_state = true;
    let runtime_mode = diagnostic
        .export_gate_runtime_mode
        .as_deref()
        .unwrap_or("unknown");
    let export_gate_reason = diagnostic
        .export_gate_reason
        .as_deref()
        .unwrap_or("unknown");

    if publication_truth_complete && fresh_under_export_gate {
        diagnostic.publication_truth_export_blocker_reason_class =
            PublicationTruthExportBlockerReasonClass::PublicationTruthExportGateSatisfied;
        diagnostic.publication_truth_export_blocker_explanation = format!(
            "publication truth export gate is currently satisfied from persisted discovery publication state: runtime_mode={runtime_mode}, reason={export_gate_reason}, publication_truth_complete=true, fresh_under_export_gate=true"
        );
        set_publication_truth_export_checkpoint_headline_not_attempted(
            diagnostic,
            "checkpoint headline enrichment was not attempted because persisted publication truth already satisfies the export gate",
        );
        set_publication_truth_export_state_json_bytes_probe_not_attempted(
            diagnostic,
            "persisted rebuild state_json byte-length probing was not attempted because checkpoint headline enrichment was not needed after the export gate was already satisfied",
        );
        set_publication_truth_export_enrichment_not_attempted(
            diagnostic,
            "bounded checkpoint/replay enrichment was not attempted because persisted publication truth already satisfies the export gate",
        );
        return PublicationTruthExportBlockerTopLevelState::GateSatisfied;
    }

    if let Some(blocker) = diagnostic
        .export_gate_reason
        .as_deref()
        .and_then(export_gate_reason_publishable_checkpoint_blocker)
    {
        diagnostic.publishable_checkpoint_blocker = Some(blocker.to_string());
        let (phase, replay_subphase, replay_incomplete) =
            infer_checkpoint_phase_and_subphase_from_blocker(blocker);
        if let Some(phase) = phase {
            diagnostic.rebuild_phase = Some(phase.to_string());
        }
        if let Some(replay_subphase) = replay_subphase {
            diagnostic.rebuild_replay_subphase = Some(replay_subphase.to_string());
        }
        if let Some(replay_incomplete) = replay_incomplete {
            diagnostic.replay_incomplete = Some(replay_incomplete);
        }
        if blocker == "replay_sol_leg_incomplete" {
            diagnostic.publication_truth_export_blocker_reason_class =
                PublicationTruthExportBlockerReasonClass::PublicationTruthExportBlockedOnReplaySolLegIncomplete;
            diagnostic.publication_truth_export_blocker_explanation = format!(
                "publication truth export is currently blocked on replay_sol_leg_incomplete as already persisted in discovery publication state: runtime_mode={runtime_mode}, reason={export_gate_reason}"
            );
            return PublicationTruthExportBlockerTopLevelState::ReplaySolLegIncomplete;
        }

        diagnostic.publication_truth_export_blocker_reason_class =
            PublicationTruthExportBlockerReasonClass::PublicationTruthExportBlockedOnOtherPublishableCheckpointReason;
        diagnostic.publication_truth_export_blocker_explanation = format!(
            "publication truth export is currently blocked on publishable checkpoint blocker {blocker} as already persisted in discovery publication state: runtime_mode={runtime_mode}, reason={export_gate_reason}"
        );
        return PublicationTruthExportBlockerTopLevelState::OtherCheckpoint(blocker.to_string());
    }

    diagnostic.publication_truth_export_blocker_reason_class =
        PublicationTruthExportBlockerReasonClass::PublicationTruthExportBlockedOnIncompleteOrStaleTruthWithoutCheckpointExplanation;
    diagnostic.publication_truth_export_blocker_explanation = format!(
        "publication truth export is currently unsatisfied without a checkpoint-coded export gate reason in persisted discovery publication state: runtime_mode={runtime_mode}, reason={export_gate_reason}, publication_truth_complete={publication_truth_complete}, fresh_under_export_gate={fresh_under_export_gate}"
    );
    set_publication_truth_export_checkpoint_headline_not_attempted(
        diagnostic,
        "checkpoint headline enrichment was not attempted because persisted discovery publication state does not encode a publishable-checkpoint blocker family",
    );
    set_publication_truth_export_state_json_bytes_probe_not_attempted(
        diagnostic,
        "persisted rebuild state_json byte-length probing was not attempted because persisted discovery publication state does not encode a publishable-checkpoint blocker family",
    );
    set_publication_truth_export_enrichment_not_attempted(
        diagnostic,
        "bounded checkpoint/replay enrichment was not attempted because persisted discovery publication state does not encode a publishable-checkpoint blocker family",
    );
    PublicationTruthExportBlockerTopLevelState::IncompleteOrStaleWithoutCheckpointExplanation
}

fn apply_publication_truth_export_checkpoint_headline_enrichment(
    diagnostic: &mut PublicationTruthExportBlockerDiagnostic,
    _top_level_state: &PublicationTruthExportBlockerTopLevelState,
    runtime_db_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_row_fetch_delay: Option<StdDuration>,
) -> PublicationTruthExportCheckpointHeadlineOutcome {
    diagnostic.publication_truth_export_checkpoint_headline_prerequisite_source =
        "direct_runtime_db_row_meta_worker_timeout_path".to_string();
    set_publication_truth_export_state_json_bytes_probe_not_attempted(
        diagnostic,
        "persisted rebuild state_json byte-length probing was skipped in the primary operator checkpoint headline path to avoid scanning large persisted state blobs before deciding whether deeper work is worthwhile",
    );

    let row_meta_load = load_publication_truth_export_checkpoint_row_meta_direct_with_budget(
        runtime_db_path,
        budget,
        #[cfg(test)]
        test_row_fetch_delay,
    );
    sync_publication_truth_export_checkpoint_headline_timing(diagnostic, &row_meta_load.timing);
    sync_publication_truth_export_checkpoint_headline_worker_telemetry(
        diagnostic,
        &row_meta_load.worker,
    );
    let row_meta = match row_meta_load.outcome {
        PublicationTruthExportCheckpointRowMetaLoadOutcome::Completed(row_meta) => row_meta,
        PublicationTruthExportCheckpointRowMetaLoadOutcome::BudgetExhausted(stage) => {
            set_publication_truth_export_checkpoint_headline_failed(
                diagnostic,
                Some(stage.as_str().to_string()),
                true,
                format!(
                    "runtime-db-only checkpoint headline enrichment exhausted its budget while running the cheap persisted rebuild row-meta path (stage={})",
                    stage.as_str()
                ),
            );
            return PublicationTruthExportCheckpointHeadlineOutcome::Failed;
        }
        PublicationTruthExportCheckpointRowMetaLoadOutcome::Error(error) => {
            set_publication_truth_export_checkpoint_headline_failed(
                diagnostic,
                Some("load_persisted_rebuild_row_meta_open_read_only".to_string()),
                false,
                format!(
                    "runtime-db-only checkpoint headline enrichment could not load cheap persisted rebuild row meta: {error}"
                ),
            );
            return PublicationTruthExportCheckpointHeadlineOutcome::Failed;
        }
    };

    diagnostic.persisted_rebuild_checkpoint_exists = Some(row_meta.checkpoint_exists);
    if let Some(updated_at) = row_meta.updated_at {
        diagnostic.persisted_rebuild_checkpoint_updated_at = Some(updated_at);
    }
    if let Some(rebuild_phase) = row_meta.rebuild_phase {
        diagnostic.rebuild_phase = Some(rebuild_phase);
    }

    let checkpoint_exists = row_meta.checkpoint_exists;
    let explanation = if checkpoint_exists {
        "runtime-db-only checkpoint headline enrichment completed from the proven cheap persisted rebuild row-meta path; state_json byte-length probing, persisted-state parsing, and recent_raw-backed replay proof were skipped on the primary operator hot path"
            .to_string()
    } else {
        "runtime-db-only checkpoint headline enrichment completed through the proven cheap persisted rebuild row-meta path and confirmed that no persisted rebuild checkpoint row is currently present"
            .to_string()
    };
    set_publication_truth_export_checkpoint_headline_completed(
        diagnostic,
        Some("complete".to_string()),
        explanation,
    );
    PublicationTruthExportCheckpointHeadlineOutcome::Completed {
        allow_deep_replay: false,
    }
}

fn load_publication_truth_export_checkpoint_row_meta_direct_with_budget(
    runtime_db_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_row_fetch_delay: Option<StdDuration>,
) -> PublicationTruthExportCheckpointRowMetaLoadResult {
    let total_started_at = Instant::now();
    let mut timing = PublicationTruthExportCheckpointHeadlineTiming::default();
    let mut worker = PublicationTruthExportCheckpointHeadlineWorkerTelemetry {
        started: true,
        ..Default::default()
    };
    let (tx, rx) = mpsc::sync_channel(16);
    let runtime_db_path = runtime_db_path.to_path_buf();
    thread::spawn(move || {
        let _ = load_publication_truth_export_checkpoint_row_meta_worker(
            &runtime_db_path,
            tx,
            #[cfg(test)]
            test_row_fetch_delay,
        );
    });

    let mut current_stage = PublicationTruthExportCheckpointRowMetaStage::SchemaLookup;
    loop {
        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::OpenedReadOnly(
                elapsed_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.opened_read_only_received = true;
                timing.runtime_db_open_elapsed_ms = elapsed_ms;
                timing.budget_remaining_ms_after_open = remaining_budget_ms(budget, total_started_at);
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::SqliteBusyTimeoutMs(
                busy_timeout_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.sqlite_busy_timeout_ms = Some(busy_timeout_ms);
            }
            Ok(PublicationTruthExportCheckpointRowMetaWorkerMessage::ConnectionReadMode {
                journal_mode,
                locking_mode,
                query_only,
            }) => {
                worker.event_count += 1;
                worker.last_event = Some("connection_read_mode_loaded".to_string());
                worker.connection_journal_mode = Some(journal_mode);
                worker.connection_locking_mode = Some(locking_mode);
                worker.connection_query_only = Some(query_only);
            }
            Ok(PublicationTruthExportCheckpointRowMetaWorkerMessage::QueryPlan {
                query_sql,
                explain_query_plan,
                explain_query_plan_rows,
                query_readonly_mode,
                row_fetch_access_path,
            }) => {
                worker.event_count += 1;
                worker.last_event = Some("query_plan_loaded".to_string());
                worker.query_sql = Some(query_sql);
                worker.explain_query_plan = Some(explain_query_plan);
                worker.explain_query_plan_rows = Some(explain_query_plan_rows);
                worker.query_readonly_mode = Some(query_readonly_mode);
                worker.row_fetch_access_path = Some(row_fetch_access_path);
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::Entered(stage)) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                current_stage = stage;
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::SchemaLookupCompleted(
                elapsed_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.schema_lookup_completed_received = true;
                timing.schema_lookup_elapsed_ms = elapsed_ms;
                timing.budget_remaining_ms_after_schema_lookup =
                    remaining_budget_ms(budget, total_started_at);
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::RowCountCompleted(
                elapsed_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.row_count_completed_received = true;
                timing.row_count_elapsed_ms = elapsed_ms;
                timing.budget_remaining_ms_after_row_count =
                    remaining_budget_ms(budget, total_started_at);
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::PrepareCompleted(
                elapsed_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.prepare_completed_received = true;
                timing.prepare_elapsed_ms = elapsed_ms;
                timing.budget_remaining_ms_after_prepare =
                    remaining_budget_ms(budget, total_started_at);
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::StepQueryStarted(
                row_fetch_started_at_unix_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.step_query_started_received = true;
                worker.row_fetch_started_at_unix_ms = Some(row_fetch_started_at_unix_ms);
                worker.row_fetch_wait_kind =
                    Some("waiting_inside_rows_next_before_first_row_or_eof".to_string());
            }
            Ok(
                message
                @ PublicationTruthExportCheckpointRowMetaWorkerMessage::StepRowFetchCompleted {
                    elapsed_ms,
                    row_returned,
                },
            ) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.step_row_fetch_completed_received = true;
                worker.row_fetch_elapsed_ms_observed_by_worker = Some(elapsed_ms);
                worker.row_fetch_wait_kind = Some(if row_returned {
                    "rows_next_returned_row".to_string()
                } else {
                    "rows_next_returned_eof".to_string()
                });
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::StepPhaseDecoded) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.step_phase_decoded_received = true;
            }
            Ok(
                message
                @ PublicationTruthExportCheckpointRowMetaWorkerMessage::StepUpdatedAtDecoded,
            ) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.step_updated_at_decoded_received = true;
            }
            Ok(message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::StepCompleted(
                elapsed_ms,
            )) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.step_completed_received = true;
                timing.step_elapsed_ms = elapsed_ms;
                timing.budget_remaining_ms_after_step = remaining_budget_ms(budget, total_started_at);
            }
            Ok(
                message @ PublicationTruthExportCheckpointRowMetaWorkerMessage::FinishedSendAttempted,
            ) => {
                worker.event_count += 1;
                worker.last_event = Some(message.event_name().to_string());
                worker.finished_send_attempted = true;
            }
            Ok(PublicationTruthExportCheckpointRowMetaWorkerMessage::Finished(result)) => {
                worker.event_count += 1;
                worker.last_event = Some("finished".to_string());
                worker.finished_received = true;
                timing.total_elapsed_ms = elapsed_ms(total_started_at);
                let outcome = match result {
                    Ok(row_meta) => PublicationTruthExportCheckpointRowMetaLoadOutcome::Completed(
                        row_meta,
                    ),
                    Err(error) => PublicationTruthExportCheckpointRowMetaLoadOutcome::Error(error),
                };
                return PublicationTruthExportCheckpointRowMetaLoadResult {
                    outcome,
                    timing,
                    worker,
                };
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                timing.total_elapsed_ms = elapsed_ms(total_started_at);
                return PublicationTruthExportCheckpointRowMetaLoadResult {
                    outcome: PublicationTruthExportCheckpointRowMetaLoadOutcome::BudgetExhausted(
                        current_stage,
                    ),
                    timing,
                    worker,
                };
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                worker.disconnected = true;
                timing.total_elapsed_ms = elapsed_ms(total_started_at);
                return PublicationTruthExportCheckpointRowMetaLoadResult {
                    outcome: PublicationTruthExportCheckpointRowMetaLoadOutcome::Error(
                        "cheap persisted rebuild row-meta worker disconnected before returning a result"
                            .to_string(),
                    ),
                    timing,
                    worker,
                };
            }
        }
    }
}

fn load_publication_truth_export_checkpoint_row_meta_worker(
    runtime_db_path: &Path,
    tx: mpsc::SyncSender<PublicationTruthExportCheckpointRowMetaWorkerMessage>,
    #[cfg(test)] test_row_fetch_delay: Option<StdDuration>,
) -> Result<()> {
    let open_started_at = Instant::now();
    let conn = Connection::open_with_flags(
        runtime_db_path,
        OpenFlags::SQLITE_OPEN_READ_ONLY | OpenFlags::SQLITE_OPEN_NO_MUTEX,
    )
    .with_context(|| {
        format!(
            "failed opening runtime sqlite db read-only for cheap checkpoint row-meta path {}",
            runtime_db_path.display()
        )
    })?;
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::OpenedReadOnly(elapsed_ms(
                open_started_at,
            )),
        )
        .is_err()
    {
        return Ok(());
    }
    let sqlite_busy_timeout_ms = conn
        .query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
        .context("failed reading sqlite busy_timeout for cheap checkpoint row-meta path")?;
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::SqliteBusyTimeoutMs(
                sqlite_busy_timeout_ms,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let connection_journal_mode = conn
        .query_row("PRAGMA journal_mode", [], |row| row.get::<_, String>(0))
        .context("failed reading sqlite journal_mode for cheap checkpoint row-meta path")?;
    let connection_locking_mode = conn
        .query_row("PRAGMA locking_mode", [], |row| row.get::<_, String>(0))
        .context("failed reading sqlite locking_mode for cheap checkpoint row-meta path")?;
    let connection_query_only = conn
        .query_row("PRAGMA query_only", [], |row| row.get::<_, i64>(0))
        .context("failed reading sqlite query_only for cheap checkpoint row-meta path")?
        != 0;
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::ConnectionReadMode {
                journal_mode: connection_journal_mode,
                locking_mode: connection_locking_mode,
                query_only: connection_query_only,
            },
        )
        .is_err()
    {
        return Ok(());
    }

    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Entered(
                PublicationTruthExportCheckpointRowMetaStage::SchemaLookup,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let schema_lookup_started_at = Instant::now();
    let table_exists = conn
        .query_row(CHECKPOINT_HEADLINE_ROW_META_TABLE_EXISTS_SQL, [], |row| {
            row.get::<_, i64>(0)
        })
        .context("failed checking discovery_persisted_rebuild_state table existence")?
        != 0;
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::SchemaLookupCompleted(
                elapsed_ms(schema_lookup_started_at),
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    if !table_exists {
        if tx
            .send(PublicationTruthExportCheckpointRowMetaWorkerMessage::FinishedSendAttempted)
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Finished(Ok(
                PublicationTruthExportCheckpointRowMeta {
                    checkpoint_exists: false,
                    rebuild_phase: None,
                    updated_at: None,
                },
            )),
        );
        return Ok(());
    }

    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Entered(
                PublicationTruthExportCheckpointRowMetaStage::RowCount,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let row_count_started_at = Instant::now();
    let row_count = conn
        .query_row(CHECKPOINT_HEADLINE_ROW_META_ROW_COUNT_SQL, [], |row| {
            row.get::<_, i64>(0)
        })
        .context("failed counting persisted rebuild checkpoint row id=1")?
        .max(0);
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::RowCountCompleted(elapsed_ms(
                row_count_started_at,
            )),
        )
        .is_err()
    {
        return Ok(());
    }
    if row_count == 0 {
        if tx
            .send(PublicationTruthExportCheckpointRowMetaWorkerMessage::FinishedSendAttempted)
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Finished(Ok(
                PublicationTruthExportCheckpointRowMeta {
                    checkpoint_exists: false,
                    rebuild_phase: None,
                    updated_at: None,
                },
            )),
        );
        return Ok(());
    }

    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Entered(
                PublicationTruthExportCheckpointRowMetaStage::PreparePrimaryKeyLookup,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let prepare_started_at = Instant::now();
    let mut stmt = conn
        .prepare(CHECKPOINT_HEADLINE_ROW_META_SQL)
        .context("failed preparing persisted rebuild checkpoint row-meta query")?;
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::PrepareCompleted(elapsed_ms(
                prepare_started_at,
            )),
        )
        .is_err()
    {
        return Ok(());
    }
    let explain_query_plan = load_checkpoint_headline_row_meta_explain_query_plan(&conn)?;
    let query_readonly_mode = stmt.readonly();
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::QueryPlan {
                query_sql: CHECKPOINT_HEADLINE_ROW_META_SQL.to_string(),
                explain_query_plan_rows: explain_query_plan.explain_query_plan_rows.clone(),
                query_readonly_mode,
                row_fetch_access_path: explain_query_plan.row_fetch_access_path.clone(),
                explain_query_plan: explain_query_plan.explain_query_plan,
            },
        )
        .is_err()
    {
        return Ok(());
    }

    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::Entered(
                PublicationTruthExportCheckpointRowMetaStage::StepPrimaryKeyLookup,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let step_started_at = Instant::now();
    let mut rows = stmt
        .query([])
        .context("failed starting persisted rebuild checkpoint row-meta query")?;
    let row_fetch_started_at_unix_ms = Utc::now().timestamp_millis();
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::StepQueryStarted(
                row_fetch_started_at_unix_ms,
            ),
        )
        .is_err()
    {
        return Ok(());
    }
    let row_fetch_started_at = Instant::now();
    #[cfg(test)]
    {
        if let Some(row_fetch_delay) = test_row_fetch_delay {
            thread::sleep(row_fetch_delay);
        }
    }
    let raw = match rows
        .next()
        .context("failed stepping persisted rebuild checkpoint row-meta query")?
    {
        Some(row) => {
            if tx
                .send(
                    PublicationTruthExportCheckpointRowMetaWorkerMessage::StepRowFetchCompleted {
                        elapsed_ms: elapsed_ms(row_fetch_started_at),
                        row_returned: true,
                    },
                )
                .is_err()
            {
                return Ok(());
            }
            let phase_raw = row
                .get::<_, String>(0)
                .context("failed decoding persisted rebuild checkpoint phase column")?;
            if tx
                .send(PublicationTruthExportCheckpointRowMetaWorkerMessage::StepPhaseDecoded)
                .is_err()
            {
                return Ok(());
            }
            let updated_at_raw = row
                .get::<_, String>(1)
                .context("failed decoding persisted rebuild checkpoint updated_at column")?;
            if tx
                .send(PublicationTruthExportCheckpointRowMetaWorkerMessage::StepUpdatedAtDecoded)
                .is_err()
            {
                return Ok(());
            }
            Some((phase_raw, updated_at_raw))
        }
        None => {
            if tx
                .send(
                    PublicationTruthExportCheckpointRowMetaWorkerMessage::StepRowFetchCompleted {
                        elapsed_ms: elapsed_ms(row_fetch_started_at),
                        row_returned: false,
                    },
                )
                .is_err()
            {
                return Ok(());
            }
            None
        }
    };
    if tx
        .send(
            PublicationTruthExportCheckpointRowMetaWorkerMessage::StepCompleted(elapsed_ms(
                step_started_at,
            )),
        )
        .is_err()
    {
        return Ok(());
    }

    let row_meta = match raw {
        Some((phase_raw, updated_at_raw)) => {
            let phase = DiscoveryPersistedRebuildPhase::parse(&phase_raw)
                .map(|phase| phase.as_str().to_string())
                .context("failed parsing persisted rebuild checkpoint phase")?;
            let updated_at = DateTime::parse_from_rfc3339(&updated_at_raw)
                .map(|value| value.with_timezone(&Utc))
                .with_context(|| {
                    format!(
                        "failed parsing persisted rebuild checkpoint updated_at as RFC3339: {}",
                        updated_at_raw
                    )
                })?;
            PublicationTruthExportCheckpointRowMeta {
                checkpoint_exists: true,
                rebuild_phase: Some(phase),
                updated_at: Some(updated_at),
            }
        }
        None => PublicationTruthExportCheckpointRowMeta {
            checkpoint_exists: false,
            rebuild_phase: None,
            updated_at: None,
        },
    };

    if tx
        .send(PublicationTruthExportCheckpointRowMetaWorkerMessage::FinishedSendAttempted)
        .is_err()
    {
        return Ok(());
    }
    let _ = tx.send(PublicationTruthExportCheckpointRowMetaWorkerMessage::Finished(Ok(row_meta)));
    Ok(())
}

struct CheckpointHeadlineExplainQueryPlan {
    explain_query_plan: String,
    explain_query_plan_rows: Vec<String>,
    row_fetch_access_path: String,
}

fn load_explain_query_plan_for_sql(
    conn: &Connection,
    sql: &str,
    context_label: &str,
) -> Result<CheckpointHeadlineExplainQueryPlan> {
    let explain_sql = format!("EXPLAIN QUERY PLAN {sql}");
    let mut stmt = conn
        .prepare(&explain_sql)
        .with_context(|| format!("failed preparing EXPLAIN QUERY PLAN for {context_label}"))?;
    let details = stmt
        .query_map([], |row| row.get::<_, String>(3))
        .with_context(|| format!("failed executing EXPLAIN QUERY PLAN for {context_label}"))?
        .collect::<rusqlite::Result<Vec<_>>>()
        .with_context(|| {
            format!("failed collecting EXPLAIN QUERY PLAN rows for {context_label}")
        })?;
    let explain_query_plan = if details.is_empty() {
        "no_query_plan_rows".to_string()
    } else {
        details.join(" | ")
    };
    let row_fetch_access_path = details
        .first()
        .cloned()
        .unwrap_or_else(|| "no_query_plan_rows".to_string());
    Ok(CheckpointHeadlineExplainQueryPlan {
        explain_query_plan,
        explain_query_plan_rows: details,
        row_fetch_access_path,
    })
}

fn load_checkpoint_headline_row_meta_explain_query_plan(
    conn: &Connection,
) -> Result<CheckpointHeadlineExplainQueryPlan> {
    load_explain_query_plan_for_sql(
        conn,
        CHECKPOINT_HEADLINE_ROW_META_SQL,
        "checkpoint row-meta query",
    )
}

