#[cfg(test)]
fn signal_checkpoint_row_fetch_direct_immutable_id_only_query_started(
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableIdOnlyProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        test_sync
            .query_started_observed
            .store(true, AtomicOrdering::SeqCst);
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_id_only_query_started(
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableIdOnlyProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    while !test_sync
        .query_started_observed
        .load(AtomicOrdering::SeqCst)
    {
        thread::sleep(StdDuration::from_millis(1));
    }
}

