fn summarize_direct_immutable_updated_at_text_vs_blob_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtTextVsBlobProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_text_vs_blob_unfinished_stage(
    text_state: &CheckpointRowFetchDirectImmutableUpdatedAtTextVsBlobSubprobeState,
    blob_state: &CheckpointRowFetchDirectImmutableUpdatedAtTextVsBlobSubprobeState,
) -> String {
    if !text_state.is_conclusive() && !text_state.finished {
        return format_direct_immutable_updated_at_text_vs_blob_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtTextVsBlobTarget::Text,
            text_state.current_stage,
        );
    }
    if !blob_state.is_conclusive() && !blob_state.finished {
        return format_direct_immutable_updated_at_text_vs_blob_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtTextVsBlobTarget::Blob,
            blob_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

