fn summarize_direct_immutable_updated_at_printf_second_char_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtPrintfSecondCharProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_printf_second_char_unfinished_stage(
    text_state: &CheckpointRowFetchDirectImmutableUpdatedAtPrintfSecondCharSubprobeState,
    unicode_state: &CheckpointRowFetchDirectImmutableUpdatedAtPrintfSecondCharSubprobeState,
) -> String {
    if !text_state.is_conclusive() && !text_state.finished {
        return format_direct_immutable_updated_at_printf_second_char_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtPrintfSecondCharTarget::Text,
            text_state.current_stage,
        );
    }
    if !unicode_state.is_conclusive() && !unicode_state.finished {
        return format_direct_immutable_updated_at_printf_second_char_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtPrintfSecondCharTarget::Unicode,
            unicode_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

