fn summarize_direct_immutable_updated_at_second_char_boundary_source_subprobe(
    label: &str,
    result_kind:
        Option<CheckpointRowFetchDirectImmutableUpdatedAtSecondCharBoundarySourceProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_second_char_boundary_source_unfinished_stage(
    printf_zero_length_state: &CheckpointRowFetchDirectImmutableUpdatedAtSecondCharBoundarySourceSubprobeState,
    unixepoch_text_zero_length_state: &CheckpointRowFetchDirectImmutableUpdatedAtSecondCharBoundarySourceSubprobeState,
) -> String {
    if !printf_zero_length_state.is_conclusive() && !printf_zero_length_state.finished {
        return format_direct_immutable_updated_at_second_char_boundary_source_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtSecondCharBoundarySourceTarget::PrintfZeroLength,
            printf_zero_length_state.current_stage,
        );
    }
    if !unixepoch_text_zero_length_state.is_conclusive()
        && !unixepoch_text_zero_length_state.finished
    {
        return format_direct_immutable_updated_at_second_char_boundary_source_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtSecondCharBoundarySourceTarget::UnixepochTextZeroLength,
            unixepoch_text_zero_length_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

