    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    let runtime_db_uri = build_sqlite_immutable_read_only_uri(&runtime_db_path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic
        .checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_text_zero_length_offset_probe_runtime_db_uri =
        Some(runtime_db_uri);
    diagnostic
        .checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_text_zero_length_offset_probe_observed =
        true;

