#[cfg(test)]
fn mark_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_text_duplicate_base_subprobe_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        match target {
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget::BaseA => {
                test_sync
                    .base_a_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget::BaseB => {
                test_sync
                    .base_b_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
        }
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_text_duplicate_base_peer_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    let peer_conclusive = match target {
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget::BaseA => {
            &test_sync.base_b_conclusive
        }
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochTextDuplicateBaseTarget::BaseB => {
            &test_sync.base_a_conclusive
        }
    };
    while !peer_conclusive.load(AtomicOrdering::SeqCst) {
        thread::sleep(StdDuration::from_millis(1));
    }
}

