fn summarize_direct_immutable_updated_at_unixepoch_int_vs_text_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_unixepoch_int_vs_text_unfinished_stage(
    unixepoch_int_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextSubprobeState,
    unixepoch_text_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextSubprobeState,
) -> String {
    if !unixepoch_int_state.is_conclusive() && !unixepoch_int_state.finished {
        return format_direct_immutable_updated_at_unixepoch_int_vs_text_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochInt,
            unixepoch_int_state.current_stage,
        );
    }
    if !unixepoch_text_state.is_conclusive() && !unixepoch_text_state.finished {
        return format_direct_immutable_updated_at_unixepoch_int_vs_text_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochText,
            unixepoch_text_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

