                        state.row_fetch_completed = true;
                        state.row_fetch_elapsed_ms = elapsed_ms;
                        state.row_returned = Some(row_returned);
                        state.unixepoch_int_value = unixepoch_int_value;
                        state.unixepoch_text_value = unixepoch_text_value;
