#[cfg(test)]
fn mark_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_int_vs_text_subprobe_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        match target {
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochInt => {
                test_sync
                    .unixepoch_int_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochText => {
                test_sync
                    .unixepoch_text_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
        }
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_int_vs_text_peer_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    let peer_conclusive = match target {
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochInt => {
            &test_sync.unixepoch_text_conclusive
        }
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochIntVsTextTarget::UnixepochText => {
            &test_sync.unixepoch_int_conclusive
        }
    };
    while !peer_conclusive.load(AtomicOrdering::SeqCst) {
        thread::sleep(StdDuration::from_millis(1));
    }
}

