fn summarize_direct_immutable_updated_at_unixepoch_duplicate_int_subprobe(
    label: &str,
    result_kind:
        Option<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

