#[cfg(test)]
fn mark_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_duplicate_int_subprobe_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        match target {
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget::UnixepochA => {
                test_sync
                    .unixepoch_a_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget::UnixepochB => {
                test_sync
                    .unixepoch_b_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
        }
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_updated_at_unixepoch_duplicate_int_peer_conclusive(
    target: CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget,
    test_sync:
        Option<&Arc<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    let peer_conclusive = match target {
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget::UnixepochA => {
            &test_sync.unixepoch_b_conclusive
        }
        CheckpointRowFetchDirectImmutableUpdatedAtUnixepochDuplicateIntTarget::UnixepochB => {
            &test_sync.unixepoch_a_conclusive
        }
    };
    while !peer_conclusive.load(AtomicOrdering::SeqCst) {
        thread::sleep(StdDuration::from_millis(1));
    }
}

