fn summarize_direct_immutable_updated_at_unixepoch_vs_phase_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsPhaseProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_unixepoch_vs_phase_unfinished_stage(
    unixepoch_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsPhaseSubprobeState,
    phase_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsPhaseSubprobeState,
) -> String {
    if !unixepoch_state.is_conclusive() && !unixepoch_state.finished {
        return format_direct_immutable_updated_at_unixepoch_vs_phase_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsPhaseTarget::Unixepoch,
            unixepoch_state.current_stage,
        );
    }
    if !phase_state.is_conclusive() && !phase_state.finished {
        return format_direct_immutable_updated_at_unixepoch_vs_phase_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsPhaseTarget::Phase,
            phase_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

