fn summarize_direct_immutable_updated_at_unixepoch_vs_typeof_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsTypeofProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_unixepoch_vs_typeof_unfinished_stage(
    unixepoch_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsTypeofSubprobeState,
    typeof_state: &CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsTypeofSubprobeState,
) -> String {
    if !unixepoch_state.is_conclusive() && !unixepoch_state.finished {
        return format_direct_immutable_updated_at_unixepoch_vs_typeof_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsTypeofTarget::Unixepoch,
            unixepoch_state.current_stage,
        );
    }
    if !typeof_state.is_conclusive() && !typeof_state.finished {
        return format_direct_immutable_updated_at_unixepoch_vs_typeof_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtUnixepochVsTypeofTarget::Typeof,
            typeof_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

