fn summarize_direct_immutable_updated_at_hex_source_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableUpdatedAtHexSourceProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_updated_at_hex_source_unfinished_stage(
    original_hex_state: &CheckpointRowFetchDirectImmutableUpdatedAtHexSourceSubprobeState,
    printf_hex_state: &CheckpointRowFetchDirectImmutableUpdatedAtHexSourceSubprobeState,
) -> String {
    if !original_hex_state.is_conclusive() && !original_hex_state.finished {
        return format_direct_immutable_updated_at_hex_source_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtHexSourceTarget::OriginalHex,
            original_hex_state.current_stage,
        );
    }
    if !printf_hex_state.is_conclusive() && !printf_hex_state.finished {
        return format_direct_immutable_updated_at_hex_source_stage(
            CheckpointRowFetchDirectImmutableUpdatedAtHexSourceTarget::PrintfHex,
            printf_hex_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

