fn probe_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_first_byte_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestBehavior,
    >,
) -> CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeDiagnostic {
    let mut diagnostic =
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeDiagnostic::unproven(
            config_path,
            "checkpoint row-fetch direct immutable started_at text-vs-blob first-byte probe did not run"
                .to_string(),
        );
    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_DIRECT_IMMUTABLE_STARTED_AT_TEXT_VS_BLOB_PROBE_BUDGET_SOURCE
            .to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    let runtime_db_uri = build_sqlite_immutable_read_only_uri(&runtime_db_path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_runtime_db_uri =
        Some(runtime_db_uri);
    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_observed = true;

    #[cfg(test)]
    let test_sync = test_behavior.map(|_| {
        Arc::new(CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestSync::default())
    });

    let (tx, rx) = mpsc::sync_channel(64);
    for target in [
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
    ] {
        let runtime_db_path_for_worker = runtime_db_path.clone();
        let tx = tx.clone();
        #[cfg(test)]
        let test_sync_for_worker = test_sync.clone();
        thread::spawn(move || {
            let _ = probe_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_worker(
                target,
                &runtime_db_path_for_worker,
                tx,
                #[cfg(test)]
                test_behavior,
                #[cfg(test)]
                test_sync_for_worker,
            );
        });
    }
    drop(tx);

    let mut text_state =
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeState::default();
    let mut blob_state =
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeState::default();

    loop {
        if text_state.is_conclusive() && blob_state.is_conclusive() {
            apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                &text_state,
                &mut diagnostic,
            );
            apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
                &blob_state,
                &mut diagnostic,
            );
            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_total_elapsed_ms =
                elapsed_ms(total_started_at);
            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_reason_class =
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeReasonClass::CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeProven;
            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                format!(
                    "direct immutable started_at text-vs-blob first-byte probe completed with bounded outcomes: {} {}",
                    summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                        "text",
                        text_state.result_kind
                    ),
                    summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                        "blob",
                        blob_state.result_kind
                    )
                );
            return diagnostic;
        }

        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(message) => {
                let state = match &message {
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::BusyTimeout {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::ConnectionReadMode {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::QueryPlan {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectQueryStarted {
                        target,
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        ..
                    } => match target {
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text => {
                            &mut text_state
                        }
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob => {
                            &mut blob_state
                        }
                    },
                };

                match message {
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                        stage,
                        ..
                    } => {
                        state.current_stage = stage;
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::BusyTimeout {
                        value,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadBusyTimeout;
                        state.busy_timeout_ms = Some(value);
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::ConnectionReadMode {
                        journal_mode,
                        locking_mode,
                        query_only,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadConnectionMetadata;
                        state.connection_journal_mode = Some(journal_mode);
                        state.connection_locking_mode = Some(locking_mode);
                        state.connection_query_only = Some(query_only);
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::QueryPlan {
                        explain_query_plan,
                        explain_query_plan_rows,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadExplainQueryPlan;
                        state.explain_query_plan = Some(explain_query_plan);
                        state.explain_query_plan_rows = Some(explain_query_plan_rows);
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectQueryStarted {
                        ..
                    } => {
                        state.query_started = true;
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectRowFetchCompleted {
                        elapsed_ms,
                        row_returned,
                        value,
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::RowFetchSelect;
                        state.row_fetch_completed = true;
                        state.row_fetch_elapsed_ms = elapsed_ms;
                        state.row_returned = Some(row_returned);
                        state.value = value;
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        result,
                        ..
                    } => match result {
                        Ok(()) => state.finished = true,
                        Err(error) => {
                            apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                                &text_state,
                                &mut diagnostic,
                            );
                            apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
                                &blob_state,
                                &mut diagnostic,
                            );
                            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_total_elapsed_ms =
                                elapsed_ms(total_started_at);
                            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_reason_class =
                                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeReasonClass::CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeUnprovenDueToMissingEvidence;
                            diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                                error;
                            return diagnostic;
                        }
                    },
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                if text_state.query_started
                    && !text_state.row_fetch_completed
                    && text_state.result_kind.is_none()
                {
                    text_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }
                if blob_state.query_started
                    && !blob_state.row_fetch_completed
                    && blob_state.result_kind.is_none()
                {
                    blob_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }

                apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                    &text_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
                    &blob_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);

                if text_state.is_conclusive() && blob_state.is_conclusive() {
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_reason_class =
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeReasonClass::CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeProven;
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                        format!(
                            "direct immutable started_at text-vs-blob first-byte probe completed with bounded outcomes: {} {}",
                            summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                                "text",
                                text_state.result_kind
                            ),
                            summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                                "blob",
                                blob_state.result_kind
                            )
                        );
                } else {
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_budget_exhausted =
                        true;
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_reason_class =
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeReasonClass::CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeBudgetExhausted;
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_stage =
                        Some(resolve_direct_immutable_started_at_text_vs_blob_unfinished_stage(
                            &text_state,
                            &blob_state,
                        ));
                    diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                        format!(
                            "checkpoint row-fetch direct immutable started_at text-vs-blob first-byte probe exhausted its bounded budget before both subprobes reached conclusive outcomes: {} {}",
                            summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                                "text",
                                text_state.result_kind
                            ),
                            summarize_direct_immutable_started_at_text_vs_blob_subprobe(
                                "blob",
                                blob_state.result_kind
                            )
                        );
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                    &text_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_started_at_text_vs_blob_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
                    &blob_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_reason_class =
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeReasonClass::CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeUnprovenDueToMissingEvidence;
                diagnostic.checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_probe_explanation =
                    "checkpoint row-fetch direct immutable started_at text-vs-blob first-byte probe workers disconnected before returning conclusive outcomes"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

fn probe_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_worker(
    target: CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget,
    runtime_db_path: &Path,
    tx: mpsc::SyncSender<CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestBehavior,
    >,
    #[cfg(test)] test_sync: Option<
        Arc<CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestSync>,
    >,
) -> Result<()> {
    let run = || -> Result<()> {
        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::OpenRuntimeDb,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let runtime_db_uri = build_sqlite_immutable_read_only_uri(runtime_db_path);
        let conn = Connection::open_with_flags(
            &runtime_db_uri,
            OpenFlags::SQLITE_OPEN_READ_ONLY
                | OpenFlags::SQLITE_OPEN_URI
                | OpenFlags::SQLITE_OPEN_NO_MUTEX,
        )
        .with_context(|| {
            format!(
                "failed opening runtime db {} for {} started_at text-vs-blob probe",
                runtime_db_path.display(),
                target.as_label()
            )
        })?;

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadBusyTimeout,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let busy_timeout_ms =
            conn.query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
                .with_context(|| {
                    format!(
                        "failed reading sqlite busy_timeout for {} started_at text-vs-blob probe",
                        target.as_label()
                    )
                })?;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::BusyTimeout {
                    target,
                    value: busy_timeout_ms,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadConnectionMetadata,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let journal_mode = conn
            .query_row("PRAGMA journal_mode", [], |row| row.get::<_, String>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite journal_mode for {} started_at text-vs-blob probe",
                    target.as_label()
                )
            })?;
        let locking_mode = conn
            .query_row("PRAGMA locking_mode", [], |row| row.get::<_, String>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite locking_mode for {} started_at text-vs-blob probe",
                    target.as_label()
                )
            })?;
        let query_only = conn
            .query_row("PRAGMA query_only", [], |row| row.get::<_, i64>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite query_only for {} started_at text-vs-blob probe",
                    target.as_label()
                )
            })?
            != 0;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::ConnectionReadMode {
                    target,
                    journal_mode,
                    locking_mode,
                    query_only,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::LoadExplainQueryPlan,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let explain_query_plan =
            load_explain_query_plan_for_sql(&conn, target.select_sql(), target.explain_context())?;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::QueryPlan {
                    target,
                    explain_query_plan: explain_query_plan.explain_query_plan,
                    explain_query_plan_rows: explain_query_plan.explain_query_plan_rows,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::PrepareSelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let mut stmt = match conn.prepare(target.select_sql()) {
            Ok(stmt) => stmt,
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure while preparing {} started_at text-vs-blob SELECT statement",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::QuerySelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let mut rows = match stmt.query([]) {
            Ok(rows) => rows,
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure while starting {} started_at text-vs-blob SELECT query",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobSubprobeStage::RowFetchSelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectQueryStarted {
                    target,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        match (target, test_behavior) {
            (
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                Some(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestBehavior::ForceTextOtherSqliteError,
                ),
            ) => {
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherSqliteError,
                        sqlite_error_code: Some("SQLITE_CORRUPT".to_string()),
                        sqlite_error_message: Some(
                            "forced other sqlite error at direct immutable text first-byte started_at SELECT rows.next() boundary".to_string(),
                        ),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            (
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text,
                Some(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestBehavior::DelayTextBeforeRowFetch(delay),
                ),
            )
            | (
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob,
                Some(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestBehavior::DelayBlobBeforeRowFetch(delay),
                ),
            ) => {
                wait_for_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_peer_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                thread::sleep(delay);
            }
            _ => {}
        }

        let row_fetch_started_at = Instant::now();
        let row = match rows.next() {
            Ok(Some(row)) => row,
            Ok(None) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                if tx
                    .send(
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectRowFetchCompleted {
                            target,
                            elapsed_ms: elapsed_ms(row_fetch_started_at),
                            row_returned: false,
                            value: None,
                            result_kind:
                                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::Eof,
                            sqlite_error_code: None,
                            sqlite_error_message: None,
                        },
                    )
                    .is_err()
                {
                    return Ok(());
                }
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure at direct immutable {} started_at text-vs-blob SELECT rows.next() boundary",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        #[cfg(test)]
        mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
            target,
            test_sync.as_ref(),
        );
        let value = match row.get::<_, Option<String>>(0) {
            Ok(value) => value,
            Err(error) => {
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        elapsed_ms: elapsed_ms(row_fetch_started_at),
                        row_returned: true,
                        value: None,
                        result_kind:
                            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::SelectRowFetchCompleted {
                    target,
                    elapsed_ms: elapsed_ms(row_fetch_started_at),
                    row_returned: true,
                    value,
                    result_kind:
                        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeResultKind::Row,
                    sqlite_error_code: None,
                    sqlite_error_message: None,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(
            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                target,
                result: Ok(()),
            },
        );
        Ok(())
    };

    if let Err(error) = run() {
        let _ = tx.send(
            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeWorkerMessage::Finished {
                target,
                result: Err(format!("{error:#}")),
            },
        );
    }
    Ok(())
}

#[cfg(test)]
fn mark_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_subprobe_conclusive(
    target: CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget,
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        match target {
            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text => {
                test_sync.text_conclusive.store(true, AtomicOrdering::SeqCst);
            }
            CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob => {
                test_sync.blob_conclusive.store(true, AtomicOrdering::SeqCst);
            }
        }
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_started_at_text_vs_blob_peer_conclusive(
    target: CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget,
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableStartedAtTextVsBlobProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    let peer_conclusive = match target {
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Text => {
            &test_sync.blob_conclusive
        }
        CheckpointRowFetchDirectImmutableStartedAtTextVsBlobTarget::Blob => {
            &test_sync.text_conclusive
        }
    };
    while !peer_conclusive.load(AtomicOrdering::SeqCst) {
        thread::sleep(StdDuration::from_millis(1));
    }
}

#[derive(Debug, Clone)]
struct CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeState {
    current_stage: CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeStage,
    explain_query_plan: Option<String>,
    explain_query_plan_rows: Option<Vec<String>>,
    connection_journal_mode: Option<String>,
    connection_locking_mode: Option<String>,
    connection_query_only: Option<bool>,
    busy_timeout_ms: Option<u64>,
    query_started: bool,
    row_fetch_completed: bool,
    row_fetch_elapsed_ms: u64,
    row_returned: Option<bool>,
    value: Option<i64>,
    result_kind: Option<CheckpointRowFetchDirectImmutableTimestampUnixepochProbeResultKind>,
    sqlite_error_code: Option<String>,
    sqlite_error_message: Option<String>,
    finished: bool,
}

impl Default for CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeState {
    fn default() -> Self {
        Self {
            current_stage:
                CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeStage::OpenRuntimeDb,
            explain_query_plan: None,
            explain_query_plan_rows: None,
            connection_journal_mode: None,
            connection_locking_mode: None,
            connection_query_only: None,
            busy_timeout_ms: None,
            query_started: false,
            row_fetch_completed: false,
            row_fetch_elapsed_ms: 0,
            row_returned: None,
            value: None,
            result_kind: None,
            sqlite_error_code: None,
            sqlite_error_message: None,
            finished: false,
        }
    }
}

impl CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeState {
    fn is_conclusive(&self) -> bool {
        self.result_kind.is_some()
    }
}

fn format_direct_immutable_timestamp_unixepoch_stage(
    target: CheckpointRowFetchDirectImmutableTimestampUnixepochTarget,
    stage: CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeStage,
) -> String {
    format!("{}_select_{}", target.as_label(), stage.as_str())
}

