fn summarize_direct_immutable_timestamp_unixepoch_subprobe(
    label: &str,
    result_kind: Option<CheckpointRowFetchDirectImmutableTimestampUnixepochProbeResultKind>,
) -> String {
    let result_kind = result_kind
        .map(|value| {
            serde_json::to_string(&value)
                .unwrap_or_else(|_| "\"unknown\"".to_string())
                .trim_matches('"')
                .to_string()
        })
        .unwrap_or_else(|| "null".to_string());
    format!("{label}_result_kind={result_kind}")
}

fn resolve_direct_immutable_timestamp_unixepoch_unfinished_stage(
    updated_at_state: &CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeState,
    started_at_state: &CheckpointRowFetchDirectImmutableTimestampUnixepochSubprobeState,
) -> String {
    if !updated_at_state.is_conclusive() && !updated_at_state.finished {
        return format_direct_immutable_timestamp_unixepoch_stage(
            CheckpointRowFetchDirectImmutableTimestampUnixepochTarget::UpdatedAt,
            updated_at_state.current_stage,
        );
    }
    if !started_at_state.is_conclusive() && !started_at_state.finished {
        return format_direct_immutable_timestamp_unixepoch_stage(
            CheckpointRowFetchDirectImmutableTimestampUnixepochTarget::StartedAt,
            started_at_state.current_stage,
        );
    }
    "wait_subprobe_results".to_string()
}

