fn probe_checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_split_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeTestBehavior,
    >,
) -> CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeDiagnostic {
    let mut diagnostic =
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeDiagnostic::unproven(
            config_path,
            "checkpoint row-fetch direct immutable timestamp textified unixepoch split probe did not run"
                .to_string(),
        );
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_DIRECT_IMMUTABLE_TIMESTAMP_TEXTIFIED_UNIXEPOCH_PROBE_BUDGET_SOURCE
            .to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic
                .checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    let runtime_db_uri = build_sqlite_immutable_read_only_uri(&runtime_db_path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic
        .checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_runtime_db_uri =
        Some(runtime_db_uri);
    diagnostic
        .checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_observed = true;

    #[cfg(test)]
    let test_sync = test_behavior.map(|_| {
        Arc::new(CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeTestSync::default())
    });

    let (tx, rx) = mpsc::sync_channel(64);
    for target in [
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt,
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt,
    ] {
        let runtime_db_path_for_worker = runtime_db_path.clone();
        let tx = tx.clone();
        #[cfg(test)]
        let test_sync_for_worker = test_sync.clone();
        thread::spawn(move || {
            let _ = probe_checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_worker(
                target,
                &runtime_db_path_for_worker,
                tx,
                #[cfg(test)]
                test_behavior,
                #[cfg(test)]
                test_sync_for_worker,
            );
        });
    }
    drop(tx);

    let mut updated_at_state =
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeState::default();
    let mut started_at_state =
        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeState::default();

    loop {
        if updated_at_state.is_conclusive() && started_at_state.is_conclusive() {
            apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt,
                &updated_at_state,
                &mut diagnostic,
            );
            apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt,
                &started_at_state,
                &mut diagnostic,
            );
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_total_elapsed_ms =
                elapsed_ms(total_started_at);
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_reason_class =
                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeProven;
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                format!(
                    "direct immutable timestamp textified unixepoch split probe completed with bounded outcomes: {} {}. This is a timestamp-textified-semantic proof operator, not a replay blocker classifier.",
                    summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                        "updated_at",
                        updated_at_state.result_kind
                    ),
                    summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                        "started_at",
                        started_at_state.result_kind
                    )
                );
            return diagnostic;
        }

        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(message) => {
                let state = match &message {
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::Entered {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::BusyTimeout {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::ConnectionReadMode {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::QueryPlan {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectQueryStarted {
                        target,
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectFailed {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::Finished {
                        target,
                        ..
                    } => match target {
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt => {
                            &mut updated_at_state
                        }
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt => {
                            &mut started_at_state
                        }
                    },
                };

                match message {
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::Entered {
                        stage,
                        ..
                    } => {
                        state.current_stage = stage;
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::BusyTimeout {
                        value,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeStage::LoadBusyTimeout;
                        state.busy_timeout_ms = Some(value);
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::ConnectionReadMode {
                        journal_mode,
                        locking_mode,
                        query_only,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeStage::LoadConnectionMetadata;
                        state.connection_journal_mode = Some(journal_mode);
                        state.connection_locking_mode = Some(locking_mode);
                        state.connection_query_only = Some(query_only);
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::QueryPlan {
                        explain_query_plan,
                        explain_query_plan_rows,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeStage::LoadExplainQueryPlan;
                        state.explain_query_plan = Some(explain_query_plan);
                        state.explain_query_plan_rows = Some(explain_query_plan_rows);
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectQueryStarted {
                        ..
                    } => {
                        state.query_started = true;
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectFailed {
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::SelectRowFetchCompleted {
                        elapsed_ms,
                        row_returned,
                        value,
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochSubprobeStage::RowFetchSelect;
                        state.row_fetch_completed = true;
                        state.row_fetch_elapsed_ms = elapsed_ms;
                        state.row_returned = Some(row_returned);
                        state.value = value;
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeWorkerMessage::Finished {
                        result,
                        ..
                    } => match result {
                        Ok(()) => state.finished = true,
                        Err(error) => {
                            apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt,
                                &updated_at_state,
                                &mut diagnostic,
                            );
                            apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt,
                                &started_at_state,
                                &mut diagnostic,
                            );
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_total_elapsed_ms =
                                elapsed_ms(total_started_at);
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_reason_class =
                                CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeUnprovenDueToMissingEvidence;
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                                error;
                            return diagnostic;
                        }
                    },
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                if updated_at_state.query_started
                    && !updated_at_state.row_fetch_completed
                    && updated_at_state.result_kind.is_none()
                {
                    updated_at_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }
                if started_at_state.query_started
                    && !started_at_state.row_fetch_completed
                    && started_at_state.result_kind.is_none()
                {
                    started_at_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }

                apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt,
                    &started_at_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);

                if updated_at_state.is_conclusive() && started_at_state.is_conclusive() {
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_reason_class =
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeProven;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                        format!(
                            "direct immutable timestamp textified unixepoch split probe completed with bounded outcomes: {} {}. This is a timestamp-textified-semantic proof operator, not a replay blocker classifier.",
                            summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                                "updated_at",
                                updated_at_state.result_kind
                            ),
                            summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                                "started_at",
                                started_at_state.result_kind
                            )
                        );
                } else {
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_budget_exhausted =
                        true;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_reason_class =
                        CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeBudgetExhausted;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_stage =
                        Some(resolve_direct_immutable_timestamp_textified_unixepoch_unfinished_stage(
                            &updated_at_state,
                            &started_at_state,
                        ));
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                        format!(
                            "checkpoint row-fetch direct immutable timestamp textified unixepoch split probe exhausted its bounded budget before both subprobes reached conclusive outcomes: {} {}. This is a timestamp-textified-semantic proof operator, not a replay blocker classifier.",
                            summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                                "updated_at",
                                updated_at_state.result_kind
                            ),
                            summarize_direct_immutable_timestamp_textified_unixepoch_subprobe(
                                "started_at",
                                started_at_state.result_kind
                            )
                        );
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_timestamp_textified_unixepoch_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochTarget::StartedAt,
                    &started_at_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_reason_class =
                    CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampTextifiedUnixepochProbeUnprovenDueToMissingEvidence;
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_textified_unixepoch_probe_explanation =
                    "checkpoint row-fetch direct immutable timestamp textified unixepoch split probe workers disconnected before returning conclusive outcomes"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

