fn probe_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_split_read_only_with_budget_impl(
    config_path: &Path,
    budget: StdDuration,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestBehavior,
    >,
) -> CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeDiagnostic {
    let mut diagnostic = CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeDiagnostic::unproven(
        config_path,
        "checkpoint row-fetch direct immutable timestamp zero-length substr split probe did not run"
            .to_string(),
    );
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_budget_ms =
        budget.as_millis().min(u64::MAX as u128) as u64;
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_budget_source =
        DEFAULT_CHECKPOINT_ROW_FETCH_DIRECT_IMMUTABLE_TIMESTAMP_ZERO_LENGTH_SUBSTR_PROBE_BUDGET_SOURCE
            .to_string();

    let total_started_at = Instant::now();
    let loaded_config = match load_from_path(config_path)
        .with_context(|| format!("failed loading config {}", config_path.display()))
    {
        Ok(config) => config,
        Err(error) => {
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                format!("{error:#}");
            return diagnostic;
        }
    };
    let runtime_db_path = resolve_db_path(config_path, None, &loaded_config.sqlite.path);
    let runtime_db_uri = build_sqlite_immutable_read_only_uri(&runtime_db_path);
    diagnostic.runtime_db_path = Some(runtime_db_path.display().to_string());
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_runtime_db_uri =
        Some(runtime_db_uri);
    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_observed = true;

    #[cfg(test)]
    let test_sync = test_behavior
        .map(|_| Arc::new(CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestSync::default()));

    let (tx, rx) = mpsc::sync_channel(64);
    for target in [
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
    ] {
        let runtime_db_path_for_worker = runtime_db_path.clone();
        let tx = tx.clone();
        #[cfg(test)]
        let test_sync_for_worker = test_sync.clone();
        thread::spawn(move || {
            let _ = probe_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_worker(
                target,
                &runtime_db_path_for_worker,
                tx,
                #[cfg(test)]
                test_behavior,
                #[cfg(test)]
                test_sync_for_worker,
            );
        });
    }
    drop(tx);

    let mut updated_at_state =
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeState::default();
    let mut started_at_state =
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeState::default();

    loop {
        if updated_at_state.is_conclusive() && started_at_state.is_conclusive() {
            apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                &updated_at_state,
                &mut diagnostic,
            );
            apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
                &started_at_state,
                &mut diagnostic,
            );
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_total_elapsed_ms =
                elapsed_ms(total_started_at);
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_reason_class =
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeProven;
            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                format!(
                    "direct immutable timestamp zero-length substr split probe completed with bounded outcomes: {} {}. This is a zero-length-substr proof operator, not a replay blocker classifier.",
                    summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                        "updated_at",
                        updated_at_state.result_kind
                    ),
                    summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                        "started_at",
                        started_at_state.result_kind
                    )
                );
            return diagnostic;
        }

        match rx.recv_timeout(remaining_budget_duration(budget, total_started_at)) {
            Ok(message) => {
                let state = match &message {
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::BusyTimeout {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::ConnectionReadMode {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::QueryPlan {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectQueryStarted {
                        target,
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        ..
                    }
                    | CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        ..
                    } => match target {
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt => {
                            &mut updated_at_state
                        }
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt => {
                            &mut started_at_state
                        }
                    },
                };

                match message {
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                        stage,
                        ..
                    } => {
                        state.current_stage = stage;
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::BusyTimeout {
                        value,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadBusyTimeout;
                        state.busy_timeout_ms = Some(value);
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::ConnectionReadMode {
                        journal_mode,
                        locking_mode,
                        query_only,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadConnectionMetadata;
                        state.connection_journal_mode = Some(journal_mode);
                        state.connection_locking_mode = Some(locking_mode);
                        state.connection_query_only = Some(query_only);
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::QueryPlan {
                        explain_query_plan,
                        explain_query_plan_rows,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadExplainQueryPlan;
                        state.explain_query_plan = Some(explain_query_plan);
                        state.explain_query_plan_rows = Some(explain_query_plan_rows);
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectQueryStarted { .. } => {
                        state.query_started = true;
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectRowFetchCompleted {
                        elapsed_ms,
                        row_returned,
                        value,
                        result_kind,
                        sqlite_error_code,
                        sqlite_error_message,
                        ..
                    } => {
                        state.current_stage =
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::RowFetchSelect;
                        state.row_fetch_completed = true;
                        state.row_fetch_elapsed_ms = elapsed_ms;
                        state.row_returned = Some(row_returned);
                        state.value = value;
                        state.result_kind = Some(result_kind);
                        state.sqlite_error_code = sqlite_error_code;
                        state.sqlite_error_message = sqlite_error_message;
                    }
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        result,
                        ..
                    } => match result {
                        Ok(()) => state.finished = true,
                        Err(error) => {
                            apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                                &updated_at_state,
                                &mut diagnostic,
                            );
                            apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
                                &started_at_state,
                                &mut diagnostic,
                            );
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_total_elapsed_ms =
                                elapsed_ms(total_started_at);
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_reason_class =
                                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeUnprovenDueToMissingEvidence;
                            diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                                error;
                            return diagnostic;
                        }
                    },
                }
            }
            Err(mpsc::RecvTimeoutError::Timeout) => {
                if updated_at_state.query_started
                    && !updated_at_state.row_fetch_completed
                    && updated_at_state.result_kind.is_none()
                {
                    updated_at_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }
                if started_at_state.query_started
                    && !started_at_state.row_fetch_completed
                    && started_at_state.result_kind.is_none()
                {
                    started_at_state.result_kind = Some(
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::RowFetchTimeoutAfterQueryStart,
                    );
                }

                apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
                    &started_at_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);

                if updated_at_state.is_conclusive() && started_at_state.is_conclusive() {
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_reason_class =
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeProven;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                        format!(
                            "direct immutable timestamp zero-length substr split probe completed with bounded outcomes: {} {}. This is a zero-length-substr proof operator, not a replay blocker classifier.",
                            summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                                "updated_at",
                                updated_at_state.result_kind
                            ),
                            summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                                "started_at",
                                started_at_state.result_kind
                            )
                        );
                } else {
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_budget_exhausted =
                        true;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_reason_class =
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeBudgetExhausted;
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_stage =
                        Some(resolve_direct_immutable_timestamp_zero_length_substr_unfinished_stage(
                            &updated_at_state,
                            &started_at_state,
                        ));
                    diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                        format!(
                            "checkpoint row-fetch direct immutable timestamp zero-length substr split probe exhausted its bounded budget before both subprobes reached conclusive outcomes: {} {}. This is a zero-length-substr proof operator, not a replay blocker classifier.",
                            summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                                "updated_at",
                                updated_at_state.result_kind
                            ),
                            summarize_direct_immutable_timestamp_zero_length_substr_subprobe(
                                "started_at",
                                started_at_state.result_kind
                            )
                        );
                }
                return diagnostic;
            }
            Err(mpsc::RecvTimeoutError::Disconnected) => {
                apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                    &updated_at_state,
                    &mut diagnostic,
                );
                apply_direct_immutable_timestamp_zero_length_substr_state_to_diagnostic(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
                    &started_at_state,
                    &mut diagnostic,
                );
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_total_elapsed_ms =
                    elapsed_ms(total_started_at);
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_reason_class =
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeReasonClass::CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeUnprovenDueToMissingEvidence;
                diagnostic.checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_probe_explanation =
                    "checkpoint row-fetch direct immutable timestamp zero-length substr split probe workers disconnected before returning conclusive outcomes"
                        .to_string();
                return diagnostic;
            }
        }
    }
}

fn probe_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_worker(
    target: CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget,
    runtime_db_path: &Path,
    tx: mpsc::SyncSender<CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage>,
    #[cfg(test)] test_behavior: Option<
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestBehavior,
    >,
    #[cfg(test)] test_sync: Option<
        Arc<CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestSync>,
    >,
) -> Result<()> {
    let run = || -> Result<()> {
        let runtime_db_uri = build_sqlite_immutable_read_only_uri(runtime_db_path);
        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::OpenRuntimeDb,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let conn = Connection::open_with_flags(
            &runtime_db_uri,
            OpenFlags::SQLITE_OPEN_READ_ONLY
                | OpenFlags::SQLITE_OPEN_URI
                | OpenFlags::SQLITE_OPEN_NO_MUTEX,
        )
        .with_context(|| {
            format!(
                "failed opening direct immutable runtime db uri {} for {} timestamp zero-length substr probe",
                runtime_db_uri,
                target.as_label()
            )
        })?;

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadBusyTimeout,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let busy_timeout_ms = conn
            .query_row("PRAGMA busy_timeout", [], |row| row.get::<_, u64>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite busy_timeout for {} timestamp zero-length substr probe",
                    target.as_label()
                )
            })?;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::BusyTimeout {
                    target,
                    value: busy_timeout_ms,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadConnectionMetadata,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let journal_mode = conn
            .query_row("PRAGMA journal_mode", [], |row| row.get::<_, String>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite journal_mode for {} timestamp zero-length substr probe",
                    target.as_label()
                )
            })?;
        let locking_mode = conn
            .query_row("PRAGMA locking_mode", [], |row| row.get::<_, String>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite locking_mode for {} timestamp zero-length substr probe",
                    target.as_label()
                )
            })?;
        let query_only = conn
            .query_row("PRAGMA query_only", [], |row| row.get::<_, i64>(0))
            .with_context(|| {
                format!(
                    "failed reading sqlite query_only for {} timestamp zero-length substr probe",
                    target.as_label()
                )
            })?
            != 0;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::ConnectionReadMode {
                    target,
                    journal_mode,
                    locking_mode,
                    query_only,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::LoadExplainQueryPlan,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let explain_query_plan =
            load_explain_query_plan_for_sql(&conn, target.select_sql(), target.explain_context())?;
        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::QueryPlan {
                    target,
                    explain_query_plan: explain_query_plan.explain_query_plan,
                    explain_query_plan_rows: explain_query_plan.explain_query_plan_rows,
                },
            )
            .is_err()
        {
            return Ok(());
        }

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::PrepareSelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let mut stmt = match conn.prepare(target.select_sql()) {
            Ok(stmt) => stmt,
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure while preparing {} timestamp zero-length substr SELECT statement",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::QuerySelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let mut rows = match stmt.query([]) {
            Ok(rows) => rows,
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure while starting {} timestamp zero-length substr SELECT query",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Entered {
                    target,
                    stage:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrSubprobeStage::RowFetchSelect,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectQueryStarted {
                    target,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        #[cfg(test)]
        match (target, test_behavior) {
            (
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                Some(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestBehavior::ForceUpdatedAtOtherSqliteError,
                ),
            ) => {
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherSqliteError,
                        sqlite_error_code: Some("SQLITE_CORRUPT".to_string()),
                        sqlite_error_message: Some(
                            "forced other sqlite error at direct immutable substr(updated_at, 1, 0) SELECT rows.next() boundary".to_string(),
                        ),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            (
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt,
                Some(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestBehavior::DelayUpdatedAtBeforeRowFetch(delay),
                ),
            )
            | (
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt,
                Some(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestBehavior::DelayStartedAtBeforeRowFetch(delay),
                ),
            ) => {
                wait_for_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_peer_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                thread::sleep(delay);
            }
            _ => {}
        }

        let row_fetch_started_at = Instant::now();
        let row = match rows.next() {
            Ok(Some(row)) => row,
            Ok(None) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                if tx
                    .send(
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectRowFetchCompleted {
                            target,
                            elapsed_ms: elapsed_ms(row_fetch_started_at),
                            row_returned: false,
                            value: None,
                            result_kind:
                                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::Eof,
                            sqlite_error_code: None,
                            sqlite_error_message: None,
                        },
                    )
                    .is_err()
                {
                    return Ok(());
                }
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(rusqlite::Error::SqliteFailure(error, message)) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind: match error.code {
                            ErrorCode::DatabaseBusy => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteBusy,
                            ErrorCode::DatabaseLocked => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::SqliteLocked,
                            _ => CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherSqliteError,
                        },
                        sqlite_error_code: Some(sqlite_error_code_name(error.code)),
                        sqlite_error_message: Some(message.unwrap_or_else(|| {
                            format!(
                                "sqlite failure at direct immutable {} timestamp zero-length substr SELECT rows.next() boundary",
                                target.as_label()
                            )
                        })),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
            Err(error) => {
                #[cfg(test)]
                mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
                    target,
                    test_sync.as_ref(),
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectFailed {
                        target,
                        result_kind:
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        #[cfg(test)]
        mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
            target,
            test_sync.as_ref(),
        );
        let value = match row.get::<_, Option<String>>(0) {
            Ok(value) => value,
            Err(error) => {
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectRowFetchCompleted {
                        target,
                        elapsed_ms: elapsed_ms(row_fetch_started_at),
                        row_returned: true,
                        value: None,
                        result_kind:
                            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::OtherError,
                        sqlite_error_code: None,
                        sqlite_error_message: Some(error.to_string()),
                    },
                );
                let _ = tx.send(
                    CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                        target,
                        result: Ok(()),
                    },
                );
                return Ok(());
            }
        };

        if tx
            .send(
                CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::SelectRowFetchCompleted {
                    target,
                    elapsed_ms: elapsed_ms(row_fetch_started_at),
                    row_returned: true,
                    value,
                    result_kind:
                        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeResultKind::Row,
                    sqlite_error_code: None,
                    sqlite_error_message: None,
                },
            )
            .is_err()
        {
            return Ok(());
        }
        let _ = tx.send(
            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                target,
                result: Ok(()),
            },
        );
        Ok(())
    };

    if let Err(error) = run() {
        let _ = tx.send(
            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeWorkerMessage::Finished {
                target,
                result: Err(format!("{error:#}")),
            },
        );
    }
    Ok(())
}

#[cfg(test)]
fn mark_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_subprobe_conclusive(
    target: CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget,
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestSync>>,
) {
    if let Some(test_sync) = test_sync {
        match target {
            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt => {
                test_sync
                    .updated_at_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
            CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt => {
                test_sync
                    .started_at_conclusive
                    .store(true, AtomicOrdering::SeqCst);
            }
        }
    }
}

#[cfg(test)]
fn wait_for_checkpoint_row_fetch_direct_immutable_timestamp_zero_length_substr_peer_conclusive(
    target: CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget,
    test_sync: Option<&Arc<CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrProbeTestSync>>,
) {
    let Some(test_sync) = test_sync else {
        return;
    };
    let peer_conclusive = match target {
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::UpdatedAt => {
            &test_sync.started_at_conclusive
        }
        CheckpointRowFetchDirectImmutableTimestampZeroLengthSubstrTarget::StartedAt => {
            &test_sync.updated_at_conclusive
        }
    };
    while !peer_conclusive.load(AtomicOrdering::SeqCst) {
        thread::sleep(StdDuration::from_millis(1));
    }
}

struct CheckpointRowFetchDirectImmutableTimestampPrintfPrefixSubprobeState {
    current_stage: CheckpointRowFetchDirectImmutableTimestampPrintfPrefixSubprobeStage,
    explain_query_plan: Option<String>,
    explain_query_plan_rows: Option<Vec<String>>,
    connection_journal_mode: Option<String>,
    connection_locking_mode: Option<String>,
    connection_query_only: Option<bool>,
    busy_timeout_ms: Option<u64>,
    query_started: bool,
    row_fetch_completed: bool,
    row_fetch_elapsed_ms: u64,
    row_returned: Option<bool>,
    value: Option<String>,
    result_kind: Option<CheckpointRowFetchDirectImmutableTimestampPrintfPrefixProbeResultKind>,
    sqlite_error_code: Option<String>,
    sqlite_error_message: Option<String>,
    finished: bool,
}

impl Default for CheckpointRowFetchDirectImmutableTimestampPrintfPrefixSubprobeState {
    fn default() -> Self {
        Self {
            current_stage:
                CheckpointRowFetchDirectImmutableTimestampPrintfPrefixSubprobeStage::OpenRuntimeDb,
            explain_query_plan: None,
            explain_query_plan_rows: None,
            connection_journal_mode: None,
            connection_locking_mode: None,
            connection_query_only: None,
            busy_timeout_ms: None,
            query_started: false,
            row_fetch_completed: false,
            row_fetch_elapsed_ms: 0,
            row_returned: None,
            value: None,
            result_kind: None,
            sqlite_error_code: None,
            sqlite_error_message: None,
            finished: false,
        }
    }
}

impl CheckpointRowFetchDirectImmutableTimestampPrintfPrefixSubprobeState {
    fn is_conclusive(&self) -> bool {
        self.result_kind.is_some()
    }
}

